return items.map(item => {
    const raw = item.json;

    // Clean keys: trim spaces and remove hidden BOM from first header
    const cleaned = {};
    Object.keys(raw).forEach(key => {
        const cleanKey = key.replace(/^\uFEFF/, '').trim(); // removes BOM and spaces
        cleaned[cleanKey] = raw[key]?.trim();
    });

    return {
        json: {
            call_time: cleaned['Call Time'] || '',
            call_id: cleaned['Caller ID'] || '',
            from: cleaned['Caller Display name'] || '',
            trunk: cleaned['Trunk'] || '',
            trunk_number: cleaned['Trunk number'] || '',
            status: cleaned['Status'] || '',
            ringing: cleaned['Ringing'] || '',
            talking: cleaned['Talking'] || '',
            total_duration: cleaned['Total Duration'] || '',
            to: cleaned['Destination Callee Id'] || '',
            destination_name: cleaned['Destination Display Name'] || '',
            cost: cleaned['Cost'] || '',
            date: cleaned['Call Time'] ? cleaned['Call Time'].split('T')[0] : ''
        }
    };
}).filter(item => item.json.call_time); // skip empty rows

return items
  .map(item => {
    const raw = item.json;

    // Skip totals rows
    if (raw.call_time === 'Totals') return null;

    // Build column_values JSON string
    const columnValues = JSON.stringify({
      text_mkybr5gz: raw.call_id || '',
      text_mkyb21ay: raw.to || '',
      text_mkybhahq: raw.direction || '',
      status: raw.status || '',
      text_mkybqcer: raw.ringing || '',
      text_mkybmhy9: raw.talking || '',
      text_mkybfa4d: raw.cost || '',
      text_mkybe5w2: raw.activity_details || '',
      date4: raw.date || ''
    });

    return {
      json: {
        query: `mutation ($board: ID!, $name: String!, $vals: JSON!) {
          create_item(board_id: $board, item_name: $name, column_values: $vals) { id }
        }`,
        variables: {
          board: 5088632639,
          name: raw.from || '', // Monday item name
          vals: columnValues
        }
      }
    };
  })
  .filter(item => item !== null); // remove nulls

