return items.map(item => {
  const raw = item.json;

  // Skip totals or invalid rows
  if (!raw.call_time) return null;

  const columnValues = {
    name: raw.from && raw.from.trim() !== '' ? raw.from : 'Inbound Call',
    date4: raw.date || '',
    status: { label: raw.status === 'Answered' ? 'Answered' : 'Unanswered' },
    text_mky3878e: raw.call_id || '',       // Caller ID
    text_mky3718k: raw.call_id || '',       // Caller Number
    text_mky3yh4m: raw.call_time || '',     // Call time
    text_mky98rqs: raw.trunk || '',         // Trunk
    numeric_mky9yfdq: Number(raw.trunk_number) || 0,
    numeric_mky9v3je: Number(raw.to) || 0, // DID
    text_mky92qps: raw.ringing || '',
    text_mky9vs9d: raw.talking || '',
    text_mky9mjrx: raw.total_duration || '',
    numeric_mkyaqsd2: 0                      // Ring Time Numbers (optional)
  };

  return {
    json: {
      query: `mutation ($board: ID!, $name: String!, $vals: JSON!) {
        create_item(board_id: $board, item_name: $name, column_values: $vals) { id }
      }`,
      variables: {
        board: 5088250215,
        name: columnValues.name,
        vals: JSON.stringify(columnValues)
      }
    }
  };
}).filter(item => item !== null);

